#include <bits/stdc++.h>
using namespace std;
class Solution { public:
    vector<int> mergeSort(vector<int>& arr1, vector<int>& arr2) {
        vector<int> merged;
        merged.insert(merged.end(), arr1.begin(), arr1.end());
        merged.insert(merged.end(), arr2.begin(), arr2.end());
        sort(merged.begin(), merged.end());
        return merged;
    }
};
